SELECT document_type, COUNT(document_type) AS document_count
FROM incident_documents
GROUP BY document_type;

SELECT COUNT(document_id) AS total_officer_notes
FROM incident_documents
WHERE document_type = 'Officer Notes';

SELECT COUNT(DISTINCT i.incident_id) AS total_incidents_with_versions
FROM incidents i
JOIN incident_versions iv ON i.incident_id = iv.incident_id;

SELECT incident_id, MAX(version_number) AS latest_version_number
FROM incident_versions
GROUP BY incident_id;

SELECT incident_id, MAX(version_number) AS latest_version
FROM incident_versions
WHERE incident_id = 0;

SELECT version_date
FROM incident_versions
WHERE incident_id = 0;
